// Icons returns all bundled icons, optionally filtered by substring queries.
// Searches both the display Name and the raw ID. All terms must match (AND semantics); matching is case-insensitive.
func Icons(q ...string) []IconEntry {
	var result []IconEntry
outer:
	for _, entry := range iconRegistry {
		haystack := strings.ToLower(entry.Name + " " + string(entry.ID))
		for _, term := range q {
			if !strings.Contains(haystack, term) {
				continue outer
			}
		}
		result = append(result, entry)
	}
	return result
}
